-- ============================================================
-- LuckyPari outreach table + import (946 leads)
-- Run this in Supabase → SQL Editor
-- ============================================================

CREATE TABLE IF NOT EXISTS lp_outreach (
  id           UUID        PRIMARY KEY DEFAULT gen_random_uuid(),
  email        TEXT        NOT NULL,
  site_name    TEXT,
  url          TEXT,
  geo          TEXT,
  lang         TEXT,
  partner_type TEXT,
  status       TEXT        NOT NULL DEFAULT 'pending',
  retry_count  INT         NOT NULL DEFAULT 0,
  scheduled_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  sent_at      TIMESTAMPTZ,
  error        TEXT,
  created_at   TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS lp_outreach_status_scheduled ON lp_outreach (status, scheduled_at);
CREATE INDEX IF NOT EXISTS lp_outreach_email            ON lp_outreach (email);

ON CONFLICT DO NOTHING;
